head.script:
scwin.vCurDate = "";
scwin.strPreDate = "";

scwin.onpageload = function() {
    scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.strPreDate = $c.date.addDate(scwin.vCurDate, -2);

    scwin.f_set("ONLOAD");

    lc_seaair.setValue("");
    lc_ioClsCd.setValue("I");
};

scwin.onUdcCompleted = function() {
    udc_eta.setInitDate(scwin.strPreDate, scwin.vCurDate);
};

scwin.f_set = function(gubun) {
    switch (gubun) {
        case "ONLOAD":
            $c.gus.cfDisableKey();
            break;

        case "RETRIEVE":
            $c.gus.cfEnableAllBtn();
            break;

        case "DELETE":
            $c.gus.cfDisableBtn();
            break;
    }
};

scwin.btn_Retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.f_Retrieve = async function() {
    let chk = await $c.gus.cfValidate([ica_etaFrom, ica_etaTo]);
    if (!chk) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(ica_etaFrom.getValue(), ica_etaTo.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["ETA From", "ETA To"]);
        ica_etaFrom.setFocus();
        return false;
    }

    if (chb_retrievalYn.getValue() != "") {
        ds_retrieve.set("retrievalYn", "1");
    } else {
        ds_retrieve.set("retrievalYn", "0");
    }

    await $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = async function(e) {
    let rowcnt = ds_retrieve_result.getRowCount();
    if (rowcnt == 0) {
        spa_totalRow.setValue(0);
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        return;
    } else {
        spa_totalRow.setValue(rowcnt);
    }
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.btSave_onclick = function(e) {
    scwin.f_Save();
};

scwin.f_Save = async function() {
    if (ds_retrieve_result.getUpdatedIndex().length == 0) {
        await $c.win.alert("변경된 내역이 없습니다.");
        return false;
    }

    for (let i = 0; i < ds_retrieve_result.getRowCount(); i++) {
        if (ds_retrieve_result.getRowStatus(i) == "U" || ds_retrieve_result.getRowStatus(i) == "C") {
            if (ds_retrieve_result.getCellData(i, "retrievalDt") == "") {
                await $c.win.alert("회수일자는 필수 입력 사항입니다.");
                return false;
            }
            if (ds_retrieve_result.getCellData(i, "blType") == "") {
                await $c.win.alert("B/L Type은 필수 입력 사항입니다.");
                return false;
            }
            if (ds_retrieve_result.getCellData(i, "retrievalDoc") == "") {
                await $c.win.alert("회수서류 종류는 필수 입력 사항입니다.");
                return false;
            }
        }
    }

    let chk = await $c.win.confirm("저장하시겠습니까?");
    if (chk) {
        await $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = async function(e) {
    await $c.win.alert("저장이 완료되었습니다.");
    scwin.f_Retrieve();
};

scwin.sbm_save_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_fileSet = async function(gubun) {
    let row = ds_retrieve_result.getRowPosition();
    let houseNo = ds_retrieve_result.getCellData(row, "hblno");

    let obj = {
        houseNo: houseNo
    };

    let resultList = await $c.win.openPopup("/ui/il/pfm/pefm/pe_116_01_01p.xml", {
        width: 870,
        height: 335,
        modal: true,
        data: obj
    });

    if (resultList != null) {
        if (resultList[0] != "" && resultList[0] != "undefined") {
            switch (gubun) {
                case 1:
                    ds_retrieve_result.setCellData(row, "evidanceFilePath", resultList[0]);
                    ds_retrieve_result.setCellData(row, "evidance", ds_retrieve_result.getCellData(row, "hblno") + "_증빙");
                    break;
                case 2:
                    ds_retrieve_result.setCellData(row, "deliveryOrderFilePath", resultList[0]);
                    ds_retrieve_result.setCellData(row, "deliveryOrder", ds_retrieve_result.getCellData(row, "hblno") + "_Delivery Order");
                    break;
            }
        }
    }
};

scwin.f_Download = async function(gubun) {
    let row = ds_retrieve_result.getRowPosition();

    if (row < 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["첨부파일 행"]);
        return;
    } else {
        switch (gubun) {
            case 1:
                let fileName1 = ds_retrieve_result.getCellData(row, "evidance");
                let filePath1 = ds_retrieve_result.getCellData(row, "evidanceFilePath");
                if (filePath1.trim().length == 0) {
                    await $c.win.alert("선택하신 " + (row + 1) + "행에 파일이 등록되어 있지 않습니다.");
                } else {
                    if (filePath1.indexOf(".") > 0) {
                        fileName1 += filePath1.substring(filePath1.indexOf("."), filePath1.indexOf(".") + 4);
                        $c.gus.cfDownloadFile(fileName1, filePath1);
                    }
                }
                break;
            case 2:
                let fileName2 = ds_retrieve_result.getCellData(row, "deliveryOrder");
                let filePath2 = ds_retrieve_result.getCellData(row, "deliveryOrderFilePath");
                if (filePath2.trim().length == 0) {
                    await $c.win.alert("선택하신 " + (row + 1) + "행에 파일이 등록되어 있지 않습니다.");
                } else {
                    if (filePath2.indexOf(".") > 0) {
                        fileName2 += filePath2.substring(filePath2.indexOf("."), filePath2.indexOf(".") + 4);
                        $c.gus.cfDownloadFile(fileName2, filePath2);
                    }
                }
                break;
        }
    }
};

scwin.btn_Clear_onclick = function(e) {
    scwin.f_FieldClear();
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([tb_retrieve]);
};

scwin.f_PopUp = function(disGubun, chgGubun) {
    switch (disGubun) {
        case "Customer":
            udc_customer.ilCommonPopUp(scwin.callbackCustomer,
                ed_customer.getValue().trim(),
                txt_customer.getValue(),
                chgGubun,
                '10',
                'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN',
                '140,300,100,100,100,100,100,,,100',
                '8,9',
                null,
                '500',
                '500',
                null,
                null,
                null,
                "F",
                'Customer search,Customer Code,Customer Name');
            break;

        case "Consignee":
            udc_consignee.ilCommonPopUp(scwin.callbackConsignee,
                ed_consignee.getValue().trim(),
                txt_consignee.getValue(),
                chgGubun,
                '10',
                'Consignee Code,Consignee Name,Address1,Address2,Address3,Address4,Tel,,,CRN',
                '140,300,100,100,100,100,100,,,100',
                '8,9',
                null,
                '500',
                '500',
                null,
                null,
                null,
                "F",
                'Consignee search,Consignee Code,Consignee Name');
            break;

        case "Notify":
            udc_notify.ilCommonPopUp(scwin.callbackNotify,
                ed_notify.getValue().trim(),
                txt_notify.getValue(),
                chgGubun,
                '10',
                'Notify Code,Notify Name,Address1,Address2,Address3,Address4,Tel,,,CRN',
                '140,300,100,100,100,100,100,,,100',
                '8,9',
                null,
                '500',
                '500',
                null,
                null,
                null,
                "F",
                'Notify search,Notify Code,Notify Name');
            break;
    }
};

scwin.callbackCustomer = function(rtnList) {
    if (rtnList) {
        $c.gus.cfSetReturnValue(rtnList, ed_customer, txt_customer);
    }
};

scwin.callbackConsignee = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_consignee, txt_consignee);
};

scwin.callbackNotify = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_notify, txt_notify);
};

scwin.f_OpenCommonPopUp = function(gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    switch (gubun1) {
        case "DEPT":
            udc_dept.ilCommonPopUp(scwin.callbackDept,
                ed_dept.getValue().trim(),
                txt_dept.getValue(),
                pWinCloseTF,
                '2',
                "Code, Name",
                '80,230',
                "3,4,5,6,7,8,9,10",
                null, null, null, null, null, null,
                pAllSearchTF,
                "DEPT,Code,Name",
                pNoDataCloseTF);
            break;
    }
};

scwin.callbackDept = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_dept, txt_dept);
};

scwin.f_downExcelSheet = async function() {
    let cntRow = ds_retrieve_result.getRowCount();

    if (cntRow != 0) {
        let cfrm = await $c.win.confirm("수입서류 관리대장 목록을 EXCEL로 다운로드 받으시겠습니까?");

        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_retrieve_result, "수입서류 관리대장", "수입서류 관리대장");
        }
    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
    }
};

scwin.f_BeforePopUpEd2 = function(nmObj, cdObj, gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    let cdObjVal = cdObj.getValue().trim();
    if (cdObjVal == "") {
        nmObj.setValue("");
    } else {
        nmObj.setValue("");
        if (gubun1 == "DEPT") {
            scwin.f_OpenCommonPopUp('DEPT', 'T', 'F', 'F');
        } else {
            scwin.f_PopUp(gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF);
        }
    }
};

scwin.ed_customer_onblur = function(e) {
    let strClntNo = ed_customer.getValue().trim();
    if (strClntNo.length > 0) {
        txt_customer.setValue("");
        scwin.f_PopUp('Customer', 'T');
    } else {
        txt_customer.setValue("");
    }
};

scwin.ed_consignee_onblur = function(e) {
    let strClntNo = ed_consignee.getValue().trim();
    if (strClntNo.length > 0) {
        txt_consignee.setValue("");
        scwin.f_PopUp('Consignee', 'T');
    } else {
        txt_consignee.setValue("");
    }
};

scwin.ed_notify_onblur = function(e) {
    let strClntNo = ed_notify.getValue().trim();
    if (strClntNo.length > 0) {
        txt_notify.setValue("");
        scwin.f_PopUp('Notify', 'T');
    } else {
        txt_notify.setValue("");
    }
};

scwin.ed_dept_onblur = function(e) {
    let strClntNo = ed_dept.getValue().trim();
    if (strClntNo.length > 0) {
        txt_dept.setValue("");
        scwin.f_OpenCommonPopUp("DEPT", "T", "F", "F");
    } else {
        txt_dept.setValue("");
    }
};

scwin.gr_retrieve_result_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    switch (columnId) {
        case "evidance":
            scwin.f_fileSet(1);
            break;
        case "deliveryOrder":
            scwin.f_fileSet(2);
            break;
    }
};

scwin.gr_retrieve_result_oncelldblclick = function(rowIndex, columnIndex, columnId) {
    switch (columnId) {
        case "evidance":
            scwin.f_Download(1);
            break;
        case "deliveryOrder":
            scwin.f_Download(2);
            break;
    }
};
